import { Component, OnInit } from '@angular/core';
import { DatabaseService } from '../../services/database';

@Component({
  selector: 'app-wallet',
  templateUrl: './wallet.page.html',
  styleUrls: ['./wallet.page.scss'],
  standalone: false
})
export class WalletPage implements OnInit {
  totalIncome: number = 0;
  incomeByMethod: { [key: string]: number } = { 'Efectivo': 0, 'Transferencia': 0 };
  bestSellers: any[] = [];

  constructor(private dbService: DatabaseService) { }

  async ngOnInit() {
    await this.loadStats();
  }

  async loadStats() {
    // Ingresos totales
    const incomeResult = await this.dbService.query('SELECT SUM(total) as total FROM orders');
    this.totalIncome = incomeResult.values?.[0].total || 0;

    // Ingresos por método de pago
    const methodResult = await this.dbService.query('SELECT payment_method, SUM(total) as subtotal FROM orders GROUP BY payment_method');
    if (methodResult.values) {
      methodResult.values.forEach((row: any) => {
        this.incomeByMethod[row.payment_method] = row.subtotal;
      });
    }

    // Productos más vendidos
    const bestSellersResult = await this.dbService.query(`
      SELECT p.name, SUM(oi.qty) as total_qty 
      FROM order_items oi 
      JOIN products p ON oi.product_id = p.id 
      GROUP BY oi.product_id 
      ORDER BY total_qty DESC 
      LIMIT 5
    `);
    this.bestSellers = bestSellersResult.values || [];
  }
}
<ion-header>
  <ion-toolbar color="primary">
    <ion-buttons slot="start">
      <ion-back-button defaultHref="/pos"></ion-back-button>
    </ion-buttons>
    <ion-title>Dashboard de Cartera</ion-title>
  </ion-toolbar>
</ion-header>

<ion-content class="ion-padding dashboard">
  <!-- Tarjeta de Ingresos Totales -->
  <ion-card class="income-card">
    <ion-card-content>
      <div class="stat-label">Ingresos Totales</div>
      <div class="stat-value">{{totalIncome | currency}}</div>
    </ion-card-content>
  </ion-card>

  <ion-row>
    <!-- Ingresos por Efectivo -->
    <ion-col size="6">
      <ion-card color="success">
        <ion-card-header>
          <ion-card-subtitle>Efectivo</ion-card-subtitle>
          <ion-card-title>{{incomeByMethod['Efectivo'] | currency}}</ion-card-title>
        </ion-card-header>
      </ion-card>
    </ion-col>
    <!-- Ingresos por Transferencia -->
    <ion-col size="6">
      <ion-card color="secondary">
        <ion-card-header>
          <ion-card-subtitle>Transferencia</ion-card-subtitle>
          <ion-card-title>{{incomeByMethod['Transferencia'] | currency}}</ion-card-title>
        </ion-card-header>
      </ion-card>
    </ion-col>
  </ion-row>

  <!-- Reporte de más vendidos -->
  <ion-card class="best-sellers-card">
    <ion-card-header>
      <ion-card-title>Top 5 Productos Más Vendidos</ion-card-title>
    </ion-card-header>
    <ion-card-content>
      <ion-list>
        <ion-item *ngFor="let prod of bestSellers; let i = index">
          <ion-badge slot="start" color="tertiary">{{i + 1}}</ion-badge>
          <ion-label>
            <h2>{{prod.name}}</h2>
            <p>{{prod.total_qty}} unidades vendidas</p>
          </ion-label>
        </ion-item>
        <ion-item *ngIf="bestSellers.length === 0">
          <ion-label>Sin ventas registradas</ion-label>
        </ion-item>
      </ion-list>
    </ion-card-content>
  </ion-card>
</ion-content>
